    const answer: number[] = new Array(n);
    for (let i = 0; i < n; i++) {
        let leftMax = 0;
        if (i > 0) {
            leftMax = prefixMax[i - 1];
        }
        let rightMax = 0;
        if (i < n - 1) {
            rightMax = suffixMax[i + 1];
        }
        let newPairLCP = 0;
        if (i > 0 && i < n - 1) {
            newPairLCP = getLCP(words[i - 1], words[i + 1]);
        }
        const currentMax = Math.max(leftMax, rightMax, newPairLCP);
        answer[i] = currentMax;
    }

    return answer;
